CustomField.formula:
IF (
  NOT (
    ISBLANK (
      TEXT(Preventive_Care_Agreement__r.Facility_Rate__r.RVU_Metric_Type__c)
    )
  ),
  TEXT(Preventive_Care_Agreement__r.Facility_Rate__r.RVU_Metric_Type__c),
  IF (
    ISPICKVAL (
      Preventive_Care_Agreement__r.ContractPaymentAgreement.Type__c,
      'Shift'
    ),
    Preventive_Care_Agreement__r.Shift__r.Shift_Full_Name__c,
    Preventive_Care_Agreement__r.Type__r.Code
  )
)
